diff --git a/lib/crates/fabro-environment/src/error.rs b/lib/crates/fabro-environment/src/error.rs
new file mode 100644
index 000000000..6557a662f
--- /dev/null
+++ b/lib/crates/fabro-environment/src/error.rs
@@ -0,0 +1,107 @@
+use std::path::PathBuf;
+
+use toml::de::Error as TomlDeError;
+use toml::ser::Error as TomlSerError;
+
+use crate::{EnvironmentId, EnvironmentRevision};
+
+#[derive(Debug, thiserror::Error)]
+pub enum EnvironmentValidationError {
+    #[error("environment id {value:?} must match [a-z0-9][a-z0-9-]{{0,62}}")]
+    InvalidEnvironmentId { value: String },
+    #[error("environment settings are invalid: {}", .errors.join("; "))]
+    InvalidSettings { errors: Vec<String> },
+    #[error("failed to read Dockerfile referenced by environment at {path:?}")]
+    DockerfileRead {
+        path: PathBuf,
+        #[source]
+        source: std::io::Error,
+    },
+}
+
+#[derive(Debug, thiserror::Error)]
+pub enum EnvironmentStoreError {
+    #[error("environment not found: {id}")]
+    NotFound { id: EnvironmentId },
+    #[error("environment already exists: {id}")]
+    AlreadyExists { id: EnvironmentId },
+    #[error("environment revision is missing: {id}")]
+    MissingRevision { id: EnvironmentId },
+    #[error("environment revision is stale for {id}: expected {expected}, actual {actual}")]
+    StaleRevision {
+        id:       EnvironmentId,
+        expected: EnvironmentRevision,
+        actual:   EnvironmentRevision,
+    },
+    #[error("environment is protected and cannot be deleted: {id}")]
+    Protected { id: EnvironmentId },
+    #[error("environment validation failed: {source}")]
+    Validation {
+        #[from]
+        source: EnvironmentValidationError,
+    },
+    #[error("invalid environment filename at {path:?}")]
+    InvalidFilename { path: PathBuf, reason: String },
+    #[error("failed to parse environment TOML at {path:?}")]
+    Parse {
+        path:   PathBuf,
+        #[source]
+        source: TomlDeError,
+    },
+    #[error("environment TOML at {path:?} is not UTF-8")]
+    InvalidUtf8 {
+        path:   PathBuf,
+        #[source]
+        source: std::str::Utf8Error,
+    },
+    #[error("failed to serialize environment TOML")]
+    Serialize {
+        #[from]
+        source: TomlSerError,
+    },
+    #[error("I/O error at {path:?}")]
+    Io {
+        path:   PathBuf,
+        #[source]
+        source: std::io::Error,
+    },
+}
+
+impl EnvironmentStoreError {
+    pub(crate) fn io(path: impl Into<PathBuf>, source: std::io::Error) -> Self {
+        Self::Io {
+            path: path.into(),
+            source,
+        }
+    }
+
+    pub(crate) fn parse(path: impl Into<PathBuf>, source: TomlDeError) -> Self {
+        Self::Parse {
+            path: path.into(),
+            source,
+        }
+    }
+
+    pub(crate) fn invalid_utf8(path: impl Into<PathBuf>, source: std::str::Utf8Error) -> Self {
+        Self::InvalidUtf8 {
+            path: path.into(),
+            source,
+        }
+    }
+
+    #[must_use]
+    pub fn kind(&self) -> &'static str {
+        match self {
+            Self::NotFound { .. } => "not_found",
+            Self::AlreadyExists { .. } => "already_exists",
+            Self::MissingRevision { .. } => "missing_revision",
+            Self::StaleRevision { .. } => "stale_revision",
+            Self::Protected { .. } => "protected",
+            Self::Validation { .. } => "validation",
+            Self::InvalidFilename { .. } => "invalid_filename",
+            Self::Parse { .. } | Self::InvalidUtf8 { .. } => "parse",
+            Self::Serialize { .. } => "serialize",
+            Self::Io { .. } => "io",
+        }
+    }
+}
diff --git a/lib/crates/fabro-environment/src/id.rs b/lib/crates/fabro-environment/src/id.rs
new file mode 100644
index 000000000..7bca49087
--- /dev/null
+++ b/lib/crates/fabro-environment/src/id.rs
@@ -0,0 +1,164 @@
+use std::fmt;
+use std::str::FromStr;
+
+use serde::de::Error as _;
+use serde::{Deserialize, Deserializer, Serialize, Serializer};
+use sha2::{Digest, Sha256};
+
+use crate::EnvironmentValidationError;
+
+#[derive(Clone, Debug, PartialEq, Eq, Hash, PartialOrd, Ord)]
+pub struct EnvironmentId(String);
+
+impl EnvironmentId {
+    pub fn new(value: impl Into<String>) -> Result<Self, EnvironmentValidationError> {
+        let value = value.into();
+        if is_valid_environment_id(&value) {
+            Ok(Self(value))
+        } else {
+            Err(EnvironmentValidationError::InvalidEnvironmentId { value })
+        }
+    }
+
+    #[must_use]
+    pub fn as_str(&self) -> &str {
+        &self.0
+    }
+}
+
+impl fmt::Display for EnvironmentId {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        f.write_str(self.as_str())
+    }
+}
+
+impl FromStr for EnvironmentId {
+    type Err = EnvironmentValidationError;
+
+    fn from_str(value: &str) -> Result<Self, Self::Err> {
+        Self::new(value)
+    }
+}
+
+impl Serialize for EnvironmentId {
+    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
+    where
+        S: Serializer,
+    {
+        serializer.serialize_str(self.as_str())
+    }
+}
+
+impl<'de> Deserialize<'de> for EnvironmentId {
+    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
+    where
+        D: Deserializer<'de>,
+    {
+        let value = String::deserialize(deserializer)?;
+        value.parse().map_err(D::Error::custom)
+    }
+}
+
+#[derive(Clone, Debug, PartialEq, Eq, Hash, PartialOrd, Ord)]
+pub struct EnvironmentRevision(String);
+
+impl EnvironmentRevision {
+    #[must_use]
+    pub fn from_bytes(bytes: &[u8]) -> Self {
+        Self(hex::encode(Sha256::digest(bytes)))
+    }
+
+    #[must_use]
+    pub fn as_str(&self) -> &str {
+        &self.0
+    }
+}
+
+impl fmt::Display for EnvironmentRevision {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        f.write_str(self.as_str())
+    }
+}
+
+impl FromStr for EnvironmentRevision {
+    type Err = EnvironmentRevisionParseError;
+
+    fn from_str(value: &str) -> Result<Self, Self::Err> {
+        if value.len() == 64
+            && value
+                .bytes()
+                .all(|byte| byte.is_ascii_digit() || (b'a'..=b'f').contains(&byte))
+        {
+            Ok(Self(value.to_string()))
+        } else {
+            Err(EnvironmentRevisionParseError(value.to_string()))
+        }
+    }
+}
+
+impl Serialize for EnvironmentRevision {
+    fn serialize<S>(&self, serializer: S) -> Result<S::Ok, S::Error>
+    where
+        S: Serializer,
+    {
+        serializer.serialize_str(self.as_str())
+    }
+}
+
+impl<'de> Deserialize<'de> for EnvironmentRevision {
+    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
+    where
+        D: Deserializer<'de>,
+    {
+        let value = String::deserialize(deserializer)?;
+        value.parse().map_err(D::Error::custom)
+    }
+}
+
+#[derive(Debug, Clone, PartialEq, Eq)]
+pub struct EnvironmentRevisionParseError(String);
+
+impl fmt::Display for EnvironmentRevisionParseError {
+    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
+        write!(f, "invalid environment revision: {:?}", self.0)
+    }
+}
+
+impl std::error::Error for EnvironmentRevisionParseError {}
+
+fn is_valid_environment_id(value: &str) -> bool {
+    let mut bytes = value.bytes();
+    let Some(first) = bytes.next() else {
+        return false;
+    };
+    if !first.is_ascii_lowercase() && !first.is_ascii_digit() {
+        return false;
+    }
+    if value.len() > 63 {
+        return false;
+    }
+    bytes.all(|byte| byte.is_ascii_lowercase() || byte.is_ascii_digit() || byte == b'-')
+}
+
+#[cfg(test)]
+mod tests {
+    use super::{EnvironmentId, EnvironmentRevision};
+
+    #[test]
+    fn environment_id_validation_matches_contract() {
+        assert!("a".parse::<EnvironmentId>().is_ok());
+        assert!("a-1".parse::<EnvironmentId>().is_ok());
+        assert!("0".parse::<EnvironmentId>().is_ok());
+        assert!("A".parse::<EnvironmentId>().is_err());
+        assert!("a_1".parse::<EnvironmentId>().is_err());
+        assert!("-a".parse::<EnvironmentId>().is_err());
+        assert!("a".repeat(64).parse::<EnvironmentId>().is_err());
+    }
+
+    #[test]
+    fn revision_requires_lowercase_sha256_hex() {
+        assert!("a".repeat(64).parse::<EnvironmentRevision>().is_ok());
+        assert!("A".repeat(64).parse::<EnvironmentRevision>().is_err());
+        assert!("a".repeat(63).parse::<EnvironmentRevision>().is_err());
+    }
+}
